## Task: Fix [medium] UI/UX: Search input still has only a placeholder, no accessible name
## Step: review-tests

### src/app.ts
```typescript
/**
 * SPA entry — wires `api`, `router`, and the DOM into a file-browser UI
 * rendered inside a native `<dialog>` widget.
 *
 * This module is the thin entry point: it builds the DOM imperatively, wires
 * toolbar/dialog events, binds the resulting element refs into the render
 * orchestrator (which owns the route dispatch and render lifecycle), and kicks
 * off the initial render. The rendering logic itself lives in the focused
 * modules under `./app/`:
 *
 *   - `./app/context.js`             — shared API client, DOM refs, render hook
 *   - `./app/dom-builders.js`        — table/breadcrumb/row/action-button builders
 *   - `./app/render-browse.js`       — browse-result rendering
 *   - `./app/render-search.js`       — search-result rendering
 *   - `./app/toolbar-handlers.js`    — search + upload handlers
 *   - `./app/render-orchestrator.js` — route dispatch + render lifecycle
 *
 * Structure (built imperatively via `document.createElement`):
 *
 *   .file-browser-host   — primary chromeless surface; hosts the widget while
 *                          the dialog is closed (embedded view)
 *   <button class="trigger">Browse Files</button>
 *   <dialog class="browser-dialog">  — frame + titlebar (dialog-only chrome)
 *     .dialog-header     — title <span> + Close icon <button>
 *     .dialog-body        — empty slot; the shared widget moves here on open
 *
 *   The shared .file-browser widget (toolbar + .results + .status) is MOVED
 *   between the embedded host and the dialog body as the dialog opens/closes.
 *   It carries no border/background/title of its own — only the dialog adds
 *   the frame + titlebar, so the embedded view is chromeless.
 *
 *   .file-browser:
 *     toolbar   — .breadcrumb + search <input> + <button> + <label> upload
 *     .results  — file/folder <table>
 *     <footer class="status"> — summary line
 *
 * All user-controlled strings (file/folder names, paths) are inserted via
 * `textContent` / element creation — never via `innerHTML` — to prevent HTML
 * injection.
 *
 * `renderBrowse` and `renderSearch` are re-exported so `src/app.test.ts`'s
 * existing `import { startApp, renderBrowse, renderSearch } from './app'`
 * continues to resolve without modification.
 */
import { doSearch, handleUpload } from './app/toolbar-handlers.js';
import { init } from './app/render-orchestrator.js';
import type { DomRefs } from './app/context.js';

export { renderBrowse } from './app/render-browse.js';
export { renderSearch } from './app/render-search.js';

/* =========================================================================
 * startApp — build the DOM, wire events, bind refs, kick off rendering
 * ========================================================================= */

export function startApp(root: HTMLElement): void {
  root.innerHTML = '';

  /* --- File-browser widget (chromeless; shared by the embedded view and the
     dialog). It owns the toolbar, results, and status. The frame and titlebar
     belong to whichever host renders it — never to the widget itself — so when
     it is embedded directly in the page it carries no border/background/title. --- */
  const widget = document.createElement('div');
  widget.className = 'file-browser';

  // Toolbar: breadcrumb, search, upload
  const toolbar = document.createElement('div');
  toolbar.className = 'toolbar';
  const breadcrumbEl = document.createElement('div');
  breadcrumbEl.className = 'breadcrumb';
  const searchInput = document.createElement('input');
  searchInput.type = 'text';
  searchInput.placeholder = 'Search...';
  const searchBtn = document.createElement('button');
  searchBtn.className = 'btn';
  searchBtn.type = 'button';
  searchBtn.textContent = 'Search';
  const uploadLabel = document.createElement('label');
  uploadLabel.className = 'btn';
  uploadLabel.textContent = 'Upload';
  const uploadInput = document.createElement('input');
  uploadInput.type = 'file';
  uploadInput.hidden = true;
  uploadInput.multiple = true;
  uploadLabel.append(uploadInput);
  toolbar.append(breadcrumbEl, searchInput, searchBtn, uploadLabel);

  // Results container + status footer
  const resultsEl = document.createElement('div');
  resultsEl.className = 'results';
  const statusEl = document.createElement('footer');
  statusEl.className = 'status';

  widget.append(toolbar, resultsEl, statusEl);

  /* --- Embedded host: the primary, chromeless surface. The widget lives here
     while the dialog is closed. --- */
  const embeddedHost = document.createElement('div');
  embeddedHost.className = 'file-browser-host';
  embeddedHost.append(widget);

  /* --- Trigger button --- */
  const trigger = document.createElement('button');
  trigger.className = 'trigger';
  trigger.textContent = 'Browse Files';

  /* --- Native <dialog>: supplies the frame (border/background) and titlebar
     (title + close). Its body is an empty slot the shared widget drops into
     when opened. --- */
  const dialog = document.createElement('dialog');
  dialog.className = 'browser-dialog';

  // Titlebar: centered title + Close (icon) button
  const header = document.createElement('div');
  header.className = 'dialog-header';
  const titleSpan = document.createElement('span');
  titleSpan.className = 'title';
  titleSpan.textContent = 'File Browser';
  const closeBtn = document.createElement('button');
  closeBtn.className = 'close-btn';
  closeBtn.type = 'button';
  // Icon button has no visible text, so expose an accessible name.
  closeBtn.setAttribute('aria-label', 'Close');
  const closeIcon = document.createElement('i');
  closeIcon.className = 'bi bi-x-lg';
  closeBtn.append(closeIcon);
  header.append(titleSpan, closeBtn);

  // Dialog body slot: the widget is moved here on open, back to the host on close.
  const dialogBody = document.createElement('div');
  dialogBody.className = 'dialog-body';

  dialog.append(header, dialogBody);
  root.append(embeddedHost, trigger, dialog);

  /* --- Event wiring --- */
  // Opening the dialog MOVES the shared widget into the dialog body (reusing
  // the same nodes, so the context refs and any in-flight render stay valid),
  // then shows it. Closing — via the close button, ESC, etc. — fires the
  // dialog's `close` event, which moves the widget back to the embedded host.
  trigger.addEventListener('click', () => {
    dialogBody.append(widget);
    dialog.showModal();
  });
  dialog.addEventListener('close', () => {
    embeddedHost.append(widget);
  });
  closeBtn.addEventListener('click', () => dialog.close());

  searchBtn.addEventListener('click', doSearch);
  searchInput.addEventListener('keydown', (event: KeyboardEvent) => {
    if (event.key === 'Enter') {
      doSearch();
    }
  });

  uploadInput.addEventListener('change', handleUpload);

  /* --- Bind refs into the orchestrator + context, subscribe, and kick off
     the initial render. --- */
  const refs: DomRefs = {
    results: resultsEl,
    status: statusEl,
    breadcrumb: breadcrumbEl,
    searchInput,
    uploadInput,
  };
  init(refs);
}

/* =========================================================================
 * Bootstrap
 *
 * Guarded so the module is importable in tests (which have no #app element)
 * without side effects. Only mounts when a real #app container exists.
 * ========================================================================= */

const appRoot = document.getElementById('app');
if (appRoot) {
  startApp(appRoot);
}

```
You are a fix agent. Resolve the following final-review finding.

Review dimension: UI/UX
Severity: medium
File: src/app.ts:71-73
Title: Search input still has only a placeholder, no accessible name

Finding:
The prior medium finding was not addressed. src/app.ts:71-73 still constructs the search input with only `searchInput.type = 'text'` and `searchInput.placeholder = 'Search...'` — there is no associated `<label>`, `aria-label`, or `title`. A placeholder is not an accessible name: it is not reliably exposed to assistive technology and disappears once the user types, leaving the field unlabeled. Screen-reader users get no clear purpose for the field. This code is part of the modified src/app.ts and remains unchanged.

Fix instructions (follow exactly; make targeted, minimal changes):
In src/app.ts where the search input is constructed (around lines 71-73), add an accessible name so the field is announced clearly by screen readers and remains labeled after the user types. The simplest fix: after `searchInput.placeholder = 'Search...';` add `searchInput.setAttribute('aria-label', 'Search files');`. Do not rely on the placeholder alone. Alternatively, add a visually-hidden `<label for>` element, but an aria-label is sufficient and consistent with the aria-label pattern used elsewhere (e.g. the dialog close button already sets aria-label). No test changes required, but if a test pins the input attributes, update it to expect the accessible name.

## Response Format (required)
Respond with ONLY a single valid JSON object matching the schema below.
- No prose, explanations, or commentary before or after the JSON.
- No markdown code fences (```), no headings — output the raw JSON object.
- Do NOT call any tools and do NOT end your turn on a thinking block. Emit the JSON object directly as text.

JSON schema:
{ approved: Whether the implementation is accepted, feedback: Detailed review feedback, issues: Array<{ file: File with the issue, description: What needs to be fixed, severity: "critical" | "minor" /* How important the fix is */ }> }

/**
 * Accessible-name tests for the search input.
 *
 * Background (the bug these tests guard against): the search `<input>` was
 * created with only a `placeholder="Search..."` and no accessible name — no
 * associated `<label for>`, no `aria-label`, no `title`. A placeholder is NOT
 * an accessible name: it is not reliably surfaced to assistive technology as
 * the field's name, and it vanishes the moment the user types, leaving the
 * field unlabeled mid-entry. Screen-reader users therefore got no clear
 * purpose for the field — a WCAG 4.1.2 (Name, Role, Value) failure.
 *
 * The fix adds `aria-label="Search files"` to the input so the field is
 * announced clearly by screen readers and remains labeled even after the user
 * types. This mirrors the `aria-label` pattern already used elsewhere in the
 * app (the dialog's icon Close button sets `aria-label="Close"`; the visually
 * hidden upload input sets `aria-label="Upload files"`).
 *
 * Environment note: happy-dom does not model the accessible-name computation
 * (it has no accessibility tree), so these tests assert the *mechanism* that
 * produces correct behavior in a real browser (a non-empty `aria-label`
 * attribute on the text input) rather than observing screen-reader output,
 * which only a real AT + browser pairing would reflect.
 */
import { describe, it, expect } from 'vitest';
import { setup, installAppTestLifecycle } from './test-helpers';

installAppTestLifecycle();

describe('search input — accessible name', () => {
  /* The field must expose an accessible name that is INDEPENDENT of its
     placeholder. A placeholder alone is insufficient: it is not reliably
     exposed as the field's accessible name, and — critically — it disappears
     once the user types, leaving the input unlabeled mid-entry. An aria-label
     is bound to the attribute, not to the field's value, so it persists. */
  describe('exposes a non-placeholder accessible name', () => {
    it('sets aria-label="Search files"', () => {
      const { searchInput } = setup();
      expect(searchInput.getAttribute('aria-label')).toBe('Search files');
    });

    it('the aria-label is a non-empty, non-whitespace string', () => {
      // Guards against a regression that sets aria-label="" or "   ", which is
      // worse than no label (an empty accessible name can override a
      // placeholder-derived name in the name computation).
      const { searchInput } = setup();
      const label = searchInput.getAttribute('aria-label') ?? '';
      expect(label.length).toBeGreaterThan(0);
      expect(label.trim().length).toBeGreaterThan(0);
    });

    it('does not rely on a <title> attribute as the sole accessible name', () => {
      // A title attribute is a poor accessible name (hover-only, ignored by
      // many screen readers by default). The contract is aria-label; pin that
      // the field is not handed off to a title tooltip instead.
      const { searchInput } = setup();
      expect(searchInput.hasAttribute('title')).toBe(false);
    });
  });

  /* The CORE of the finding: the label must persist after the user types. The
     placeholder cannot do this; an aria-label must. Setting `.value` (the
     equivalent of typing) must not alter the attribute. */
  describe('the accessible name persists after the user types', () => {
    it('retains aria-label="Search files" once the field holds a value', () => {
      const { searchInput } = setup();
      searchInput.value = 'report.pdf';
      expect(searchInput.getAttribute('aria-label')).toBe('Search files');
    });

    it('retains aria-label="Search files" after the field is cleared', () => {
      // After the user clears what they typed, the placeholder may reappear
      // visually — but the aria-label must never have depended on it.
      const { searchInput } = setup();
      searchInput.value = 'something';
      searchInput.value = '';
      expect(searchInput.getAttribute('aria-label')).toBe('Search files');
    });
  });

  /* The fix ADDS an accessible name; it must not remove the placeholder (which
     still serves as a visible affordance for sighted users) nor alter the
     input's type. These guard against an over-eager edit that swaps the
     placeholder for a label and loses the visible hint. */
  describe('the placeholder and input type are preserved', () => {
    it('still carries the Search... placeholder', () => {
      const { searchInput } = setup();
      expect(searchInput.getAttribute('placeholder')).toBe('Search...');
    });

    it('is still a text input', () => {
      const { searchInput } = setup();
      expect(searchInput.type).toBe('text');
    });
  });

  /* The field must not be excluded from the accessibility tree, which would
     nullify the label entirely. */
  describe('is not excluded from the accessibility tree', () => {
    it('does not set aria-hidden', () => {
      const { searchInput } = setup();
      expect(searchInput.getAttribute('aria-hidden')).toBeNull();
    });

    it('does not carry a negative tabindex that would remove it from the tab order', () => {
      const { searchInput } = setup();
      expect(searchInput.getAttribute('tabindex')).not.toBe('-1');
    });
  });

  /* There is exactly one text search input, so the accessible-name contract is
     unambiguous and is not satisfied by some other unlabeled field. */
  describe('there is a single labeled search input', () => {
    it('the document contains exactly one text input, and it is the labeled one', () => {
      const { root, searchInput } = setup();
      const textInputs = root.querySelectorAll('input[type="text"]');
      expect(textInputs).toHaveLength(1);
      expect(textInputs[0]).toBe(searchInput);
      expect(textInputs[0].getAttribute('aria-label')).toBe('Search files');
    });
  });
});

/**
 * Tests for `src/app.ts`'s module surface and `startApp` bootstrap: the
 * imperative DOM scaffold it builds, the dialog open/close + shared-widget
 * move wiring, and the two characterization suites that pin app.ts's retained
 * imports and its (dead-)CSS-selector-relevant DOM output.
 *
 * Split out of the former `src/app.test.ts` monolith (task-29). The shared
 * fixtures, DOM scaffolding, and the per-test fetch stub come from
 * `./test-helpers`.
 *
 * Environment: the project-default `happy-dom` (these tests need a DOM).
 *
 * Contract decisions encoded by these suites (carried over from the monolith):
 *  - The action controls Delete / Move / Copy are `<button>` elements whose
 *    trimmed `textContent` is exactly `"Delete"` / `"Move"` / `"Copy"`.
 *  - Importing `./app` must not side-effect when there is no `#app` element.
 */
import { describe, it, expect, vi } from 'vitest';
import { startApp, renderBrowse, renderSearch } from '../app';
import { toBrowseHash, toSearchHash } from '../router';
import {
  setup,
  setupCleared,
  flush,
  browseResult,
  fileEntry,
  cellsOf,
  rowByName,
  clickNameLink,
  dataRows,
  browseRoute,
  searchRoute,
  installAppTestLifecycle,
} from './test-helpers';

installAppTestLifecycle();

/* ===========================================================================
 * Module surface / bootstrap guard
 * ========================================================================= */
describe('app module surface', () => {
  it('exports startApp, renderBrowse, and renderSearch as functions', () => {
    expect(typeof startApp).toBe('function');
    expect(typeof renderBrowse).toBe('function');
    expect(typeof renderSearch).toBe('function');
  });

  it('can be imported without a DOM #app element present (bootstrap is guarded)', () => {
    // Importing this test file already imported '../app'. That import ran the
    // bootstrap line `const root = document.getElementById('app'); if (root)
    // startApp(root);` against an empty document and did not throw — reaching
    // this assertion proves the guard. We additionally assert there is no
    // stray dialog created at module load time.
    expect(document.querySelector('dialog.browser-dialog')).toBeNull();
  });
});

/* ===========================================================================
 * startApp — DOM structure & dialog wiring
 * ========================================================================= */
describe('startApp', () => {
  describe('DOM structure', () => {
    it('creates a trigger button labelled "Browse Files"', () => {
      const { trigger } = setup();
      expect(trigger).toBeTruthy();
      expect(trigger.className).toBe('trigger');
      expect(trigger.textContent?.trim()).toBe('Browse Files');
    });

    it('creates a native <dialog class="browser-dialog"> that starts closed', () => {
      const { dialog } = setup();
      expect(dialog).toBeTruthy();
      expect(dialog.tagName).toBe('DIALOG');
      expect(dialog.className).toBe('browser-dialog');
      expect(dialog.open).toBe(false);
    });

    it('renders a header with a centered title span and an icon Close button', () => {
      const { dialog, closeBtn } = setup();
      expect(closeBtn).toBeTruthy();
      expect(closeBtn.className).toBe('close-btn');
      // No visible text — it's an icon button, so it carries an aria-label.
      expect(closeBtn.textContent?.trim()).toBe('');
      expect(closeBtn.getAttribute('aria-label')).toBe('Close');
      const icon = closeBtn.querySelector('.bi');
      expect(icon).toBeTruthy();
      expect(icon?.className).toContain('bi-x-lg');
      expect(dialog.contains(closeBtn)).toBe(true);
      const titleSpan = dialog.querySelector('.title');
      expect(titleSpan).toBeTruthy();
      expect(titleSpan?.textContent).toBe('File Browser');
    });

    it('renders a toolbar with a breadcrumb container', () => {
      const { breadcrumb } = setup();
      expect(breadcrumb).toBeTruthy();
      expect(breadcrumb.className).toBe('breadcrumb');
    });

    it('renders a search text input with the Search... placeholder, an accessible name, and a Search button', () => {
      const { searchInput, searchBtn } = setup();
      expect(searchInput).toBeTruthy();
      expect(searchInput.type).toBe('text');
      expect(searchInput.getAttribute('placeholder')).toBe('Search...');
      // A placeholder is not an accessible name (it is not reliably surfaced
      // to AT and disappears once the user types), so the input must also
      // expose an aria-label. (Full contract: search-a11y.test.ts.)
      expect(searchInput.getAttribute('aria-label')).toBe('Search files');
      expect(searchBtn).toBeTruthy();
      expect(searchBtn.textContent?.trim()).toBe('Search');
      expect(searchBtn.className).toBe('btn');
    });

    it('renders an upload control: label.btn wrapping a visually-hidden, multiple file input', () => {
      const { uploadLabel, uploadInput } = setup();
      expect(uploadLabel).toBeTruthy();
      expect(uploadLabel.className).toBe('btn');
      expect(uploadLabel.textContent).toContain('Upload');
      expect(uploadInput).toBeTruthy();
      expect(uploadInput.type).toBe('file');
      // Keyboard accessibility (WCAG 2.1.1): the input must NOT carry the
      // `hidden` HTML attribute — UA `display:none` would eject it from the
      // tab order, leaving the Upload control unreachable via keyboard. It is
      // visually hidden via the `visually-hidden` sr-only class instead, and
      // exposes an accessible name. (Full contract: upload-a11y.test.ts.)
      expect(uploadInput.hasAttribute('hidden')).toBe(false);
      expect(uploadInput.className).toContain('visually-hidden');
      expect(uploadInput.getAttribute('aria-label')).toBe('Upload files');
      expect(uploadInput.hasAttribute('multiple')).toBe(true);
      expect(uploadLabel.contains(uploadInput)).toBe(true);
    });

    it('renders an empty .results container and a .status footer', () => {
      const { results, status } = setup();
      expect(results).toBeTruthy();
      expect(results.className).toBe('results');
      expect(status).toBeTruthy();
      expect(status.tagName).toBe('FOOTER');
      expect(status.className).toBe('status');
    });
  });

  describe('dialog open/close wiring', () => {
    it('opens the dialog (showModal) when the trigger is clicked', () => {
      const { dialog, trigger } = setup();
      const showSpy = vi.spyOn(dialog, 'showModal');

      trigger.click();

      expect(showSpy).toHaveBeenCalledTimes(1);
      expect(dialog.open).toBe(true);
    });

    it('closes the dialog when the Close button is clicked', () => {
      const { dialog, closeBtn } = setup();
      dialog.showModal();
      expect(dialog.open).toBe(true);
      const closeSpy = vi.spyOn(dialog, 'close');

      closeBtn.click();

      expect(closeSpy).toHaveBeenCalledTimes(1);
      expect(dialog.open).toBe(false);
    });
  });

  /* The file browser is a single chromeless widget shared between the embedded
     host (primary view) and the dialog body. Opening the dialog MOVES the same
     nodes into the dialog; closing moves them back — so there is never a second
     copy, and the embedded view stays chromeless (no frame/title). */
  describe('shared widget (embedded host vs dialog)', () => {
    it('renders an embedded host and a single chromeless .file-browser widget', () => {
      const { embeddedHost, widget } = setup();
      expect(embeddedHost).toBeTruthy();
      expect(embeddedHost.className).toBe('file-browser-host');
      expect(widget).toBeTruthy();
      expect(widget.className).toBe('file-browser');
      // There is exactly one widget in the whole document.
      expect(document.querySelectorAll('.file-browser')).toHaveLength(1);
    });

    it('hosts the widget in the embedded host while the dialog is closed', () => {
      const { embeddedHost, widget, dialog } = setup();
      expect(embeddedHost.contains(widget)).toBe(true);
      // The widget (and thus its table/search/status) is NOT inside the dialog
      // until the dialog is opened.
      expect(dialog.contains(widget)).toBe(false);
    });

    it('moves the widget into the dialog body when the dialog opens', () => {
      const { embeddedHost, widget, dialog, trigger } = setup();

      trigger.click();

      expect(dialog.open).toBe(true);
      expect(dialog.contains(widget)).toBe(true);
      // Same node reference, not a clone — only one widget exists.
      expect(document.querySelectorAll('.file-browser')).toHaveLength(1);
      expect(embeddedHost.contains(widget)).toBe(false);
    });

    it('moves the widget back to the embedded host when the dialog closes', () => {
      const { embeddedHost, widget, dialog, trigger } = setup();
      trigger.click();
      expect(dialog.contains(widget)).toBe(true);

      dialog.close();

      expect(dialog.open).toBe(false);
      expect(embeddedHost.contains(widget)).toBe(true);
      expect(dialog.contains(widget)).toBe(false);
    });

    it('the embedded widget carries no dialog chrome (no title/close-btn)', () => {
      const { widget } = setup();
      // The titlebar (title + close button) is dialog-only chrome; the embedded
      // widget must not contain a title or close button.
      expect(widget.querySelector('.title')).toBeNull();
      expect(widget.querySelector('.close-btn')).toBeNull();
      expect(widget.querySelector('.dialog-header')).toBeNull();
    });
  });
});

/* ===========================================================================
 * Import characterization (safety net for unused-import removal)
 *
 * `src/app.ts` imports `parseHash` (from ./router.js), `parentPath`, and
 * `basename` (from ./format.js) that are never referenced in the module body
 * and are slated for removal. Removing unused imports cannot change runtime
 * behavior, so these tests guard the OTHER behaviors: they pin the observable
 * outputs that depend on the imports which STAY — especially the ones that
 * share an import line with the removed names, where a careless edit could
 * drop a needed sibling. Each assertion checks a concrete value tied to one
 * retained import's real usage in the app; if that import were removed, the
 * referenced call would throw (ReferenceError) or emit wrong output and the
 * test would fail.
 *
 * Retained imports exercised here:
 *   format.js: joinPath, normalizeRelativePath, formatBytes, formatDate
 *   router.js: toBrowseHash, toSearchHash
 * (getCurrentRoute / subscribe / navigate are already covered by the render
 * orchestration and toolbar-handler suites.)
 * ========================================================================= */
describe('import characterization (KEEP-list behaviors)', () => {
  // Local leaf finder; the breadcrumb describe has its own scoped copy.
  function leafByText(container: Element, text: string): HTMLElement | undefined {
    return Array.from(container.querySelectorAll('*')).find(
      (el) => el.children.length === 0 && (el.textContent ?? '').trim() === text,
    ) as HTMLElement | undefined;
  }

  /* --- format.js KEEP imports (siblings of the removed parentPath/basename) --- */

  describe('joinPath (breadcrumb cumulative paths)', () => {
    it('joins each cumulative segment across three path levels', async () => {
      const { breadcrumb } = await setupCleared();
      renderBrowse(browseResult({ path: 'a/b/c', entries: [] }));

      leafByText(breadcrumb, 'c')!.click();
      expect(window.location.hash).toBe(toBrowseHash('a/b/c'));

      leafByText(breadcrumb, 'b')!.click();
      expect(window.location.hash).toBe(toBrowseHash('a/b'));
    });
  });

  describe('normalizeRelativePath (breadcrumb path cleaning)', () => {
    it('collapses leading/doubled/trailing slashes before splitting segments', async () => {
      const { breadcrumb } = await setupCleared();
      renderBrowse(browseResult({ path: '//a//b//' }));

      leafByText(breadcrumb, 'b')!.click();
      expect(window.location.hash).toBe(toBrowseHash('a/b'));
    });
  });

  describe('formatBytes (size column)', () => {
    it('renders a 0-byte file as "0 B" (sub-KB integer branch)', async () => {
      const entry = fileEntry({ name: 'empty.txt', path: 'docs/empty.txt', size: 0 });
      const { results } = await setupCleared();
      renderBrowse(browseResult({ path: 'docs', entries: [entry] }));

      const sizeCell = cellsOf(rowByName(results.querySelector('table')!, 'empty.txt')!)[1];
      expect(sizeCell.textContent?.trim()).toBe('0 B');
    });
  });

  describe('formatDate (modified column)', () => {
    it('renders an empty Modified cell when lastModified is empty (fallback)', async () => {
      const entry = fileEntry({ name: 'nodate.txt', path: 'docs/nodate.txt', lastModified: '' });
      const { results } = await setupCleared();
      renderBrowse(browseResult({ path: 'docs', entries: [entry] }));

      const modifiedCell = cellsOf(rowByName(results.querySelector('table')!, 'nodate.txt')!)[2];
      expect(modifiedCell.textContent).toBe('');
    });
  });

  /* --- router.js KEEP imports (siblings of the removed parseHash) --- */

  describe('toBrowseHash (per-segment percent-encoding)', () => {
    it('encodes spaces in directory names when navigating into a folder', async () => {
      const dir = fileEntry({ name: 'my folder', path: 'docs/my folder', isDirectory: true });
      const { results } = await setupCleared();
      renderBrowse(browseResult({ path: 'docs', entries: [dir] }));

      clickNameLink(rowByName(results.querySelector('table')!, 'my folder')!);

      expect(window.location.hash).toBe('#/browse/docs/' + encodeURIComponent('my folder'));
      expect(window.location.hash).toBe(toBrowseHash('docs/my folder'));
    });
  });

  describe('toSearchHash (query/path percent-encoding)', () => {
    it('encodes special characters in the search query and scope path', async () => {
      const { searchInput, searchBtn } = setup({ hash: toBrowseHash('docs') });
      await flush();

      searchInput.value = 'a & b=c?';
      searchBtn.click();

      const expected =
        '#/search?q=' + encodeURIComponent('a & b=c?') + '&path=' + encodeURIComponent('docs');
      expect(window.location.hash).toBe(expected);
      expect(window.location.hash).toBe(toSearchHash('a & b=c?', 'docs'));
    });
  });
});

/* ===========================================================================
 * Dead CSS selector characterization
 *
 * `src/app.css` ships rule blocks whose selectors are NEVER emitted by app.ts,
 * so they have ZERO observable effect on the rendered UI. They are slated for
 * deletion in a dead-code cleanup. The tests below pin the JS-side invariants
 * that make that deletion provably safe:
 *
 *   - the rendered DOM must never produce an element the removed selectors
 *     could match; and
 *   - any behavior the dead rules *appear* to supply must actually be provided
 *     by an independent mechanism that survives the deletion.
 *
 * Removed selectors under test:
 *   (1) `.results-table .folder-row td`  — no table row is ever given the
 *       `folder-row` class.
 *   (2) `.breadcrumb .separator`         — breadcrumb separators are class-less
 *       `<span>`s holding the literal "/"; nothing carries `separator`.
 *   (3) `.toolbar label.upload-btn` (+ its `:hover` + the descendant
 *       `input[type=file]` rule) — the upload label uses `btn`, never
 *       `upload-btn`, so the dead descendant selector never matched the
 *       wrapped file input. (The input is now visually hidden via the
 *       `visually-hidden` sr-only class — see upload-a11y.test.ts — not via
 *       the `hidden` attribute nor the dead `display:none` descendant rule.)
 *
 * These assertions pass against the current (pre-cleanup) code AND must keep
 * passing after the dead rules are deleted, because they depend only on the
 * DOM app.ts emits — which the cleanup does not touch. (The environment does
 * not load app.css, so a missing rule cannot change `getComputedStyle` here;
 * these tests instead prove the rule could never have matched anything.)
 *
 * NOTE: these tests pass a `Route` fixture (`browseRoute` / `searchRoute`) as
 * a second argument to `renderBrowse` / `renderSearch`. That argument is a
 * leftover from before the route parameter was removed (see the
 * route-independence suite in `render-orchestration.test.ts`) and is silently
 * ignored at runtime; it is preserved verbatim so the scenario is unchanged.
 * ========================================================================= */
describe('dead CSS selector characterization', () => {
  describe('folder rows never carry the dead `.folder-row` class', () => {
    it('browse rows (folder, file, and the ".." parent) all have an empty className and no `folder-row`', async () => {
      const dir = fileEntry({ name: 'sub', path: 'docs/sub', isDirectory: true });
      const file = fileEntry({ name: 'a.txt', path: 'docs/a.txt', isDirectory: false });
      const { results } = await setupCleared();
      renderBrowse(
        browseResult({ path: 'docs/sub', parent: 'docs', entries: [dir, file] }),
        browseRoute('docs/sub'),
      );

      const rows = dataRows(results.querySelector('table')!);
      // parent + folder + file = 3 rows, so the assertions below are meaningful.
      expect(rows).toHaveLength(3);
      for (const row of rows) {
        expect(row.className).toBe('');
        expect(row.classList.contains('folder-row')).toBe(false);
      }
      // The dead selector `.results-table .folder-row td` matches nothing.
      expect(document.querySelectorAll('.folder-row')).toHaveLength(0);
    });

    it('search rows also never carry the `folder-row` class', async () => {
      const dir = fileEntry({ name: 'd', path: 'docs/d', isDirectory: true });
      const file = fileEntry({ name: 'f.txt', path: 'docs/f.txt', isDirectory: false });
      const { results } = await setupCleared();
      renderSearch({ query: 'q', path: '', results: [dir, file] }, searchRoute('q'));

      const rows = dataRows(results.querySelector('table')!);
      expect(rows).toHaveLength(2);
      for (const row of rows) {
        expect(row.classList.contains('folder-row')).toBe(false);
      }
      expect(document.querySelectorAll('.folder-row')).toHaveLength(0);
    });
  });

  describe('breadcrumb separators are class-less spans (no `.separator`)', () => {
    /** Leaf <span>s whose visible text is exactly the breadcrumb slash. */
    function slashSeparators(container: Element): HTMLSpanElement[] {
      return Array.from(container.querySelectorAll('span')).filter(
        (s) => (s.textContent ?? '').trim() === '/',
      ) as HTMLSpanElement[];
    }

    it('renders one "/" separator per path segment, each a class-less <span>', async () => {
      const { breadcrumb } = await setupCleared();
      renderBrowse(browseResult({ path: 'a/b/c', entries: [] }), browseRoute('a/b/c'));

      const separators = slashSeparators(breadcrumb);
      // a/b/c → 3 segments → 3 separators (Home / a / b / c). Verifying the
      // count also pins that the separators are still visibly rendered.
      expect(separators).toHaveLength(3);
      for (const sep of separators) {
        expect(sep.tagName).toBe('SPAN');
        expect(sep.className).toBe('');
        expect(sep.classList.contains('separator')).toBe(false);
      }
      // The dead selector `.breadcrumb .separator` matches nothing.
      expect(document.querySelectorAll('.separator')).toHaveLength(0);
    });

    it('renders no separators for the root path, and still no `.separator` anywhere', async () => {
      const { breadcrumb } = await setupCleared();
      renderBrowse(browseResult({ path: '', entries: [] }), browseRoute(''));

      expect(slashSeparators(breadcrumb)).toHaveLength(0);
      expect(document.querySelectorAll('.separator')).toHaveLength(0);
    });

    it('search-scope breadcrumbs also use class-less "/" separators', async () => {
      const { breadcrumb } = await setupCleared();
      renderSearch({ query: 'q', path: 'x/y', results: [] }, searchRoute('q', 'x/y'));

      const separators = slashSeparators(breadcrumb);
      expect(separators).toHaveLength(2);
      for (const sep of separators) {
        expect(sep.className).toBe('');
        expect(sep.classList.contains('separator')).toBe(false);
      }
      expect(document.querySelectorAll('.separator')).toHaveLength(0);
    });
  });

  describe('upload control never carries the dead `upload-btn` class', () => {
    it('the upload label uses `btn` (styled by .btn), and no element is `upload-btn`', () => {
      const { uploadLabel } = setup();
      expect(uploadLabel.className).toBe('btn');
      expect(uploadLabel.classList.contains('upload-btn')).toBe(false);
      // The dead selector `.toolbar label.upload-btn` matches nothing.
      expect(document.querySelectorAll('.upload-btn')).toHaveLength(0);
    });

    it('hides the file input via the `visually-hidden` class — NOT the dead `display:none` rule, NOT the `hidden` attribute', () => {
      const { uploadInput, uploadLabel } = setup();
      // The input is visually hidden via the `visually-hidden` sr-only class
      // (a clip-to-1x1 pattern that keeps it focusable for keyboard users),
      // NOT via the `hidden` HTML attribute — which would apply UA
      // `display:none` and eject the control from the tab order (the
      // keyboard-inaccessibility bug fixed separately; see upload-a11y.test.ts).
      expect(uploadInput.hidden).toBe(false);
      expect(uploadInput.hasAttribute('hidden')).toBe(false);
      expect(uploadInput.className).toContain('visually-hidden');
      // The dead descendant rule `.toolbar label.upload-btn input[type=file]
      // { display: none; }` still cannot match this input: its label ancestor
      // is `btn`, never `upload-btn`, so the selector never applied regardless
      // of the input's own class. Deleting that dead rule cannot un-hide it.
      expect(uploadLabel.classList.contains('upload-btn')).toBe(false);
    });
  });
});

/**
 * Shared test helpers for the `src/app/*.test.ts` per-domain test files.
 *
 * Extracted verbatim from the former `src/app.test.ts` monolith (split per
 * task-29) so each focused test file can import only what it needs. Houses:
 *
 *   - fixture builders: `fileEntry`, `browseResult`, `joinPathHelper`,
 *     `browseRoute`, `searchRoute`
 *   - timing: `flush`
 *   - DOM scaffolding: `setup`, `setupCleared`, `SetupCtx`
 *   - table/row traversal: `dataRows`, `rowByName`, `cellsOf`,
 *     `clickNameLink`, `buttonsByText`
 *   - the shared per-test fetch stub lifecycle: `installAppTestLifecycle` plus
 *     the `fetchMock` live binding it rebinds each test
 *
 * `browseRoute` / `searchRoute` construct `Route` fixtures. They were
 * referenced by the dead-CSS characterization suite in the monolith but never
 * defined (a latent bug that left those tests throwing `ReferenceError`); they
 * are defined here so those scenarios finally run. `renderBrowse` /
 * `renderSearch` no longer take a `route` argument (its removal is pinned by
 * the route-independence suite), so the value is ignored at runtime — but it
 * must be a defined expression rather than a bare `ReferenceError`.
 *
 * Test-only utility: deliberately kept out of the production `tsc` build via
 * the `src/app/test-helpers.ts` entry in `tsconfig.json`'s `exclude` array
 * (mirroring the `src/test-utils/**` glob added by task-27), so it is never
 * shipped to `wwwroot/dist`. Only test files import it.
 */
import { vi, beforeEach, afterEach } from 'vitest';
import { startApp } from '../app';
import type { BrowseResult, FileEntry, SearchResult } from '../api';
import type { Route } from '../router';
import { mockResponse } from '../test-utils/mock-response';

/* ===========================================================================
 * Constants & fixture builders
 * ========================================================================= */

export const ISO = '2024-03-15T10:30:00'; // offset-free → parsed as local time
export const ISO_FMT = '2024-03-15 10:30'; // expected formatDate(...) output

export function fileEntry(opts: Partial<FileEntry> & { name: string }): FileEntry {
  return {
    name: opts.name,
    path: opts.path ?? joinPathHelper('docs', opts.name),
    isDirectory: opts.isDirectory ?? false,
    size: opts.size ?? 0,
    lastModified: opts.lastModified ?? ISO,
  };
}

export function browseResult(opts: Partial<BrowseResult> = {}): BrowseResult {
  return {
    path: opts.path ?? '',
    parent: opts.parent ?? null,
    entries: opts.entries ?? [],
    folderCount: opts.folderCount ?? 0,
    fileCount: opts.fileCount ?? 0,
    totalSize: opts.totalSize ?? 0,
  };
}

// local join to avoid pulling joinPath into the test's asserted import set
export function joinPathHelper(base: string, name: string): string {
  return (base ? base + '/' : '') + name;
}

/** Build a browse `Route` fixture. */
export function browseRoute(path: string): Route {
  return { view: 'browse', path, query: '' };
}

/** Build a search `Route` fixture. */
export function searchRoute(query: string, path: string = ''): Route {
  return { view: 'search', query, path };
}

/* ===========================================================================
 * Timing
 * ========================================================================= */

/** Let pending microtasks / queued hashchange renders settle. */
export const flush = (): Promise<void> => new Promise((r) => setTimeout(r, 0));

/* ===========================================================================
 * DOM scaffolding
 * ========================================================================= */

export interface SetupCtx {
  root: HTMLElement;
  embeddedHost: HTMLElement;
  widget: HTMLElement;
  dialog: HTMLDialogElement;
  trigger: HTMLButtonElement;
  closeBtn: HTMLButtonElement;
  breadcrumb: HTMLElement;
  searchInput: HTMLInputElement;
  searchBtn: HTMLButtonElement;
  uploadLabel: HTMLLabelElement;
  uploadInput: HTMLInputElement;
  results: HTMLElement;
  status: HTMLElement;
}

/**
 * Build a fresh app inside a fresh container. Clears `document.body` first so
 * every test is independent (no leakage of elements, and document-scoped
 * queries inside `renderBrowse`/`renderSearch` always resolve to the current
 * test's DOM).
 */
export function setup(options: { hash?: string } = {}): SetupCtx {
  document.body.innerHTML = '';
  window.location.hash = options.hash ?? '';

  const root = document.createElement('div');
  document.body.append(root);
  startApp(root);

  const button = (text: string): HTMLButtonElement | undefined =>
    Array.from(root.querySelectorAll('button')).find(
      (b) => (b.textContent ?? '').trim() === text,
    ) as HTMLButtonElement | undefined;

  return {
    root,
    embeddedHost: root.querySelector('.file-browser-host') as HTMLElement,
    widget: root.querySelector('.file-browser') as HTMLElement,
    dialog: root.querySelector('dialog.browser-dialog') as HTMLDialogElement,
    trigger: root.querySelector('button.trigger') as HTMLButtonElement,
    closeBtn: root.querySelector('.close-btn') as HTMLButtonElement,
    breadcrumb: root.querySelector('.breadcrumb') as HTMLElement,
    searchInput: root.querySelector('input[type="text"]') as HTMLInputElement,
    searchBtn: button('Search') as HTMLButtonElement,
    uploadLabel: root.querySelector('label.btn') as HTMLLabelElement,
    uploadInput: root.querySelector('input[type="file"]') as HTMLInputElement,
    results: root.querySelector('.results') as HTMLElement,
    status: root.querySelector('.status') as HTMLElement,
  };
}

/**
 * `setup()` plus a flush (so startApp's initial `render()` settles) and a clear
 * of `.results`, mimicking what `render()` does before delegating to
 * `renderBrowse`/`renderSearch`. Used by tests that exercise those helpers
 * directly so their assertions are isolated from the initial render's output.
 */
export async function setupCleared(options: { hash?: string } = {}): Promise<SetupCtx> {
  const ctx = setup(options);
  await flush();
  ctx.results.innerHTML = '';
  return ctx;
}

/* ===========================================================================
 * Table-traversal helpers (browser-agnostic; work on Element).
 * ========================================================================= */

export function dataRows(table: Element): Element[] {
  return Array.from(table.querySelectorAll('tbody tr'));
}
export function rowByName(table: Element, name: string): Element | undefined {
  return dataRows(table).find(
    (tr) => (tr.querySelector('td')?.textContent ?? '').trim() === name,
  );
}
export function cellsOf(row: Element): Element[] {
  return Array.from(row.querySelectorAll('td'));
}
export function clickNameLink(row: Element): void {
  const nameCell = cellsOf(row)[0];
  const link = nameCell.querySelector('a, button') as HTMLElement | null;
  (link ?? (nameCell as HTMLElement)).click();
}
export function buttonsByText(container: Element, text: string): HTMLButtonElement[] {
  return Array.from(container.querySelectorAll('button')).filter(
    (b) => (b.textContent ?? '').trim() === text,
  );
}

/* ===========================================================================
 * Shared per-test fetch stub lifecycle
 *
 * `fetchMock` is an `export let` live binding: `installAppTestLifecycle()`'s
 * `beforeEach` rebinds it to a fresh permissive `vi.fn` each test, and every
 * importer sees the rebound value (ESM live bindings — verified against this
 * vitest setup). Tests therefore read `fetchMock.mock.calls` exactly as the
 * monolith did, with no per-file `let fetchMock` declaration.
 * ========================================================================= */

export let fetchMock: ReturnType<typeof vi.fn> = vi.fn(async () =>
  mockResponse({ body: {} }),
);

/**
 * Register the shared `beforeEach` (permissive default fetch stub) and
 * `afterEach` (DOM + mock cleanup) used by every split app test file. Call
 * exactly once at module top level in each `*.test.ts`.
 */
export function installAppTestLifecycle(): void {
  beforeEach(() => {
    // A permissive default: every browse/search GET returns a recognizable
    // result derived from the requested path/query, and every mutation returns
    // 200. Individual tests override with `fetchMock.mockImplementation(...)`
    // or `.mockResolvedValueOnce(...)` for specific scenarios. This also means
    // incidental background renders (e.g. from accumulated hashchange
    // listeners) never throw unhandled rejections.
    fetchMock = vi.fn(async (url: string, init?: RequestInit) => {
      const u = String(url);
      const method = (init?.method ?? 'GET').toUpperCase();
      if (method === 'GET' && u.includes('/browse')) {
        const raw = u.split('path=')[1] ?? '';
        const path = decodeURIComponent(raw);
        const childName = 'child-of-' + (path || 'root');
        return mockResponse({
          body: browseResult({
            path,
            entries: [fileEntry({ name: childName, path: joinPathHelper(path, childName) })],
            fileCount: 1,
            totalSize: 10,
          }),
        });
      }
      if (method === 'GET' && u.includes('/search')) {
        const afterQuery = u.slice(u.indexOf('query=') + 6);
        const query = decodeURIComponent(afterQuery.split('&')[0]);
        return mockResponse({
          body: {
            query,
            path: '',
            results: [fileEntry({ name: 'result-for-' + query, path: joinPathHelper('docs', 'result-for-' + query) })],
          } as SearchResult,
        });
      }
      return mockResponse({ status: 200, body: {} });
    });
    vi.stubGlobal('fetch', fetchMock);
  });

  afterEach(() => {
    // NOTE: do NOT touch window.location.hash here. In happy-dom, assigning to
    // location.hash dispatches `hashchange` synchronously. startApp unsubscribes
    // the previous mount's render() listener on re-mount (so listeners no longer
    // accumulate across tests), but the CURRENT test's listener remains active
    // until the next test's setup() re-mounts. Resetting the hash after
    // `vi.unstubAllGlobals()` would therefore drive a render through the REAL
    // fetch. We clear the body first (while fetch is still stubbed, so any
    // in-flight render's already-issued request stays mocked) and reset the hash
    // at the start of the next test's setup() instead.
    document.body.innerHTML = '';
    vi.unstubAllGlobals();
    vi.restoreAllMocks();
  });
}

/**
 * Keyboard-accessibility tests for the Upload control.
 *
 * Background (the bug these tests guard against): the file input was created
 * with `uploadInput.hidden = true`, which sets the HTML `hidden` attribute.
 * The UA stylesheet maps `[hidden]` to `display:none`, and a `display:none`
 * form control is removed from the tab order and cannot receive focus. The
 * only visible Upload affordance is a wrapping `<label class="btn">`, and
 * `<label>` elements are neither focusable nor activatable from the keyboard
 * on their own. Net effect: keyboard-only and screen-reader users could not
 * reach or trigger Upload — a WCAG 2.1.1 (Keyboard) failure — while mouse
 * users could (a `<label>` click forwards to its wrapped input).
 *
 * The fix keeps the input in the accessibility tree and tab order by hiding
 * it *visually* with the standard `visually-hidden` (sr-only) clip pattern
 * rather than the `hidden` attribute, and gives it an `aria-label` so it has
 * an accessible name. Because the `<label class="btn">` still wraps the input,
 * Tab moves focus onto the (visually hidden) input inside the visible Upload
 * button, and Enter/Space opens the file picker.
 *
 * These tests pin the JS-side contract emitted by `startApp`. The matching
 * CSS contract — that `.visually-hidden` clips rather than `display:none`s the
 * element, and that the Upload label shows a focus ring via `:focus-within` —
 * lives in `src/app.css.test.ts`.
 *
 * Environment note: happy-dom does NOT model the UA `display:none` for
 * `[hidden]` (a hidden input still reports `getComputedStyle(...).display` as
 * `inline-block`) nor enforce the "hidden elements cannot receive focus"
 * rule. These tests therefore assert the *mechanism* that produces correct
 * behavior in a real browser (no `hidden` attribute + `visually-hidden` class
 * + accessible name) rather than trying to observe tab-order / focus-ring
 * rendering, which only a real browser would reflect.
 */
import { describe, it, expect } from 'vitest';
import { setup, installAppTestLifecycle } from './test-helpers';

installAppTestLifecycle();

describe('upload control — keyboard accessibility', () => {
  /* The input must remain in the tab order. The `hidden` HTML attribute is the
     exact mechanism that broke keyboard access (UA display:none), so its
     absence is the core assertion of this suite. */
  describe('the file input is NOT removed from the tab order', () => {
    it('does not carry the `hidden` HTML attribute', () => {
      const { uploadInput } = setup();
      expect(uploadInput.hasAttribute('hidden')).toBe(false);
    });

    it('the `hidden` IDL property is false', () => {
      const { uploadInput } = setup();
      expect(uploadInput.hidden).toBe(false);
    });

    it('is visually hidden via the `visually-hidden` sr-only class instead', () => {
      const { uploadInput } = setup();
      expect(uploadInput.classList.contains('visually-hidden')).toBe(true);
    });

    it('is not given a negative tabindex that would also remove it from the tab order', () => {
      const { uploadInput } = setup();
      // A file input with no tabindex is naturally focusable; tabindex="-1"
      // would be a different way to reintroduce the same keyboard failure.
      expect(uploadInput.getAttribute('tabindex')).not.toBe('-1');
    });

    it('resolves to a non-negative tabIndex (naturally in the sequential focus order)', () => {
      const { uploadInput } = setup();
      // The attribute-string check above only rejects the literal `"-1"`; a
      // stray tabindex="-2" / "-5" (which ALSO removes the control from the
      // sequential focus order) would slip through it. The resolved IDL
      // `tabIndex` covers every negative value: it is 0 for an inherently
      // focusable control with no attribute, and the parsed integer otherwise.
      expect(uploadInput.tabIndex).toBeGreaterThanOrEqual(0);
    });

    it('is not `disabled` (a disabled form control is also unfocusable)', () => {
      const { uploadInput } = setup();
      // `disabled` is a distinct vector for the same WCAG 2.1.1 failure: a
      // disabled input cannot receive focus and is skipped by Tab. The fix must
      // keep the control enabled regardless of how it is hidden visually.
      expect(uploadInput.disabled).toBe(false);
      expect(uploadInput.hasAttribute('disabled')).toBe(false);
    });

    it('carries no inline `style` declaring display:none or visibility:hidden', () => {
      const { uploadInput } = setup();
      // The class-based `visually-hidden` fix is the only intended hiding
      // mechanism. An inline `style="display:none"` (or `visibility:hidden`)
      // would re-introduce the tab-order failure independently of the class, so
      // guard against a regression that adds either via the style property.
      const inlineStyle = uploadInput.getAttribute('style') ?? '';
      expect(/display\s*:\s*none/.test(inlineStyle)).toBe(false);
      expect(/visibility\s*:\s*hidden/.test(inlineStyle)).toBe(false);
    });
  });

  /* An unnamed form control is announced generically by screen readers (e.g.
     "file upload button"). The visible text lives on the wrapping label, but
     the input itself — the actual focus target — needs its own accessible
     name now that it is the element Tab lands on. */
  describe('the file input has an accessible name', () => {
    it('exposes aria-label="Upload files"', () => {
      const { uploadInput } = setup();
      expect(uploadInput.getAttribute('aria-label')).toBe('Upload files');
    });

    it('does not also set aria-hidden (which would exclude it from the a11y tree)', () => {
      const { uploadInput } = setup();
      expect(uploadInput.getAttribute('aria-hidden')).toBeNull();
    });
  });

  /* The visible Upload affordance must still wrap the input so the label's
     click-forwarding and visible "Upload" text keep working for mouse and AT
     users, and so Tab lands inside the visible button. */
  describe('the visible Upload label still wraps the input', () => {
    it('the input is a descendant of the label.btn "Upload" affordance', () => {
      const { uploadLabel, uploadInput } = setup();
      expect(uploadLabel.className).toBe('btn');
      expect(uploadLabel.textContent).toContain('Upload');
      expect(uploadLabel.contains(uploadInput)).toBe(true);
    });

    it('there is exactly one file input, nested inside the Upload label', () => {
      const { root, uploadInput, uploadLabel } = setup();
      const fileInputs = root.querySelectorAll('input[type="file"]');
      expect(fileInputs).toHaveLength(1);
      expect(fileInputs[0]).toBe(uploadInput);
      expect(uploadLabel.contains(fileInputs[0])).toBe(true);
    });
  });

  /* The hiding mechanism is the ONLY thing that changes; the control's type,
     multiplicity, and name must be preserved. */
  describe('upload behavior is preserved', () => {
    it('retains type=file and multiple', () => {
      const { uploadInput } = setup();
      expect(uploadInput.type).toBe('file');
      expect(uploadInput.hasAttribute('multiple')).toBe(true);
    });
  });
});

/**
 * Characterization tests for `src/app.ts` — pin the EXACT observable behavior
 * (DOM structure, element attributes, child ordering, and render-lifecycle
 * semantics) that the upcoming split into `src/app/*` domain modules must
 * preserve.
 *
 * Why this file exists alongside `src/app.test.ts`:
 *   The behavioral suite (`app.test.ts`) is thorough on user-facing scenarios
 *   but asserts many DOM-construction details only loosely (via `toContain` on
 *   text, or via click→hash side effects rather than the DOM itself). Those
 *   loose assertions are precisely what a STRUCTURAL refactor can silently
 *   break — e.g. dropping a `class`, reordering toolbar children, setting an
 *   attribute via a property instead of `setAttribute`, or wiring the shared
 *   status-element ref incorrectly when bare module-level `let`s become a
 *   context object. The tests here pin those details exactly so the split is
 *   provably behavior-preserving.
 *
 * Every assertion is driven through the PUBLIC API (`startApp` /
 * `renderBrowse` / `renderSearch` / synthesized user events) so the tests stay
 * valid no matter how the internals are reorganized into
 * `dom-builders.ts`, `render-browse.ts`, `render-search.ts`,
 * `toolbar-handlers.ts`, and `render-orchestrator.ts`.
 *
 * Environment: project-default happy-dom (these tests need a DOM).
 */
import { describe, it, expect, beforeEach, afterEach, vi } from 'vitest';
import { startApp, renderBrowse, renderSearch } from './app';
import type { BrowseResult, FileEntry, SearchResult } from './api';
import { toBrowseHash, navigate } from './router';
import { formatBytes, formatDate } from './format';

/* ===========================================================================
 * Shared helpers (self-contained so this file is independent of app.test.ts)
 * ========================================================================= */

/** Minimal fetch `Response` stand-in for the stubbed global `fetch`. */
function mockResponse(opts: {
  ok?: boolean;
  status?: number;
  body?: unknown;
  text?: string;
}): Response {
  const status = opts.status ?? 200;
  const ok = opts.ok ?? (status >= 200 && status < 300);
  const text = opts.text ?? JSON.stringify(opts.body ?? {});
  return {
    ok,
    status,
    text: async () => text,
    json: async () => (opts.body ?? {}),
  } as unknown as Response;
}

const ISO = '2024-03-15T10:30:00'; // offset-free → parsed as local time
const ISO_FMT = '2024-03-15 10:30'; // expected formatDate(...) output

function fileEntry(opts: Partial<FileEntry> & { name: string }): FileEntry {
  return {
    name: opts.name,
    path: opts.path ?? `docs/${opts.name}`,
    isDirectory: opts.isDirectory ?? false,
    size: opts.size ?? 0,
    lastModified: opts.lastModified ?? ISO,
  };
}

function browseResult(opts: Partial<BrowseResult> = {}): BrowseResult {
  return {
    path: opts.path ?? '',
    parent: opts.parent ?? null,
    entries: opts.entries ?? [],
    folderCount: opts.folderCount ?? 0,
    fileCount: opts.fileCount ?? 0,
    totalSize: opts.totalSize ?? 0,
  };
}

/** Let pending microtasks / queued hashchange renders settle. */
const flush = (): Promise<void> => new Promise((r) => setTimeout(r, 0));

interface Ctx {
  root: HTMLElement;
  widget: HTMLElement;
  toolbar: HTMLElement;
  breadcrumb: HTMLElement;
  searchInput: HTMLInputElement;
  searchBtn: HTMLButtonElement;
  uploadLabel: HTMLLabelElement;
  uploadInput: HTMLInputElement;
  results: HTMLElement;
  status: HTMLElement;
}

/**
 * Build a fresh app inside a fresh container (clears `document.body` first so
 * every test is independent), then return typed handles to the key elements.
 */
function setup(options: { hash?: string } = {}): Ctx {
  document.body.innerHTML = '';
  window.location.hash = options.hash ?? '';

  const root = document.createElement('div');
  document.body.append(root);
  startApp(root);

  const button = (text: string): HTMLButtonElement =>
    Array.from(root.querySelectorAll('button')).find(
      (b) => (b.textContent ?? '').trim() === text,
    ) as HTMLButtonElement;

  return {
    root,
    widget: root.querySelector('.file-browser') as HTMLElement,
    toolbar: root.querySelector('.toolbar') as HTMLElement,
    breadcrumb: root.querySelector('.breadcrumb') as HTMLElement,
    searchInput: root.querySelector('input[type="text"]') as HTMLInputElement,
    searchBtn: button('Search'),
    uploadLabel: root.querySelector('label.btn') as HTMLLabelElement,
    uploadInput: root.querySelector('input[type="file"]') as HTMLInputElement,
    results: root.querySelector('.results') as HTMLElement,
    status: root.querySelector('.status') as HTMLElement,
  };
}

/**
 * `setup()` plus a flush (so startApp's initial `render()` settles) and a clear
 * of `.results`, mirroring what `render()` does before delegating to
 * `renderBrowse`/`renderSearch`. Used by tests that exercise those helpers
 * directly so their assertions are isolated from the initial render's output.
 */
async function setupCleared(options: { hash?: string } = {}): Promise<Ctx> {
  const ctx = setup(options);
  await flush();
  ctx.results.innerHTML = '';
  return ctx;
}

/* Table-traversal helpers. */
function dataRows(table: Element): Element[] {
  return Array.from(table.querySelectorAll('tbody tr'));
}
function rowByName(table: Element, name: string): Element {
  const row = dataRows(table).find(
    (tr) => (tr.querySelector('td')?.textContent ?? '').trim() === name,
  );
  if (!row) throw new Error(`no row named ${name}`);
  return row;
}
function cellsOf(row: Element): Element[] {
  return Array.from(row.querySelectorAll('td'));
}
function buttonsByText(container: Element, text: string): HTMLButtonElement[] {
  return Array.from(container.querySelectorAll('button')).filter(
    (b) => (b.textContent ?? '').trim() === text,
  );
}

/* ===========================================================================
 * Test lifecycle
 * ========================================================================= */

let fetchMock: ReturnType<typeof vi.fn>;

beforeEach(() => {
  // Permissive default: browse/search GETs return recognizable results derived
  // from the requested path/query; mutations return 200. Individual tests
  // override as needed. This also keeps incidental background renders (from
  // any lingering hashchange listener) from throwing unhandled rejections.
  fetchMock = vi.fn(async (url: string, init?: RequestInit) => {
    const u = String(url);
    const method = (init?.method ?? 'GET').toUpperCase();
    if (method === 'GET' && u.includes('/browse')) {
      const raw = u.split('path=')[1] ?? '';
      const path = decodeURIComponent(raw);
      const child = 'child-of-' + (path || 'root');
      return mockResponse({
        body: browseResult({
          path,
          entries: [fileEntry({ name: child, path: `${path}/${child}` })],
          fileCount: 1,
          totalSize: 10,
        }),
      });
    }
    if (method === 'GET' && u.includes('/search')) {
      const afterQuery = u.slice(u.indexOf('query=') + 6);
      const query = decodeURIComponent(afterQuery.split('&')[0]);
      return mockResponse({
        body: {
          query,
          path: '',
          results: [fileEntry({ name: 'result-for-' + query, path: `docs/result-for-${query}` })],
        } as SearchResult,
      });
    }
    return mockResponse({ status: 200, body: {} });
  });
  vi.stubGlobal('fetch', fetchMock);
});

afterEach(() => {
  // Clear the body while fetch is still stubbed (so any in-flight render's
  // already-issued request stays mocked), then restore globals. The hash is
  // reset at the start of the next setup() — never here (see app.test.ts for
  // the rationale: resetting it here would drive a render through real fetch).
  document.body.innerHTML = '';
  vi.unstubAllGlobals();
  vi.restoreAllMocks();
});

/* ===========================================================================
 * buildTable — exact table structure
 *
 * Pinned because `buildTable` is being extracted verbatim into
 * `dom-builders.ts`; a dropped class name or restructured thead/tbody would
 * change the DOM the tests in app.test.ts rely on (tbody-traversal helpers).
 * ========================================================================= */
describe('buildTable (table structure)', () => {
  it('gives the table the class "results-table"', async () => {
    const { results } = await setupCleared();
    renderBrowse(browseResult({ path: 'docs', entries: [] }));
    expect(results.querySelector('table')!.className).toBe('results-table');
  });

  it('builds a <thead> with exactly one <tr> holding one <th> per header', async () => {
    const { results } = await setupCleared();
    renderBrowse(browseResult({ path: 'docs', entries: [] }));
    const table = results.querySelector('table')!;
    const theadRows = table.querySelectorAll('thead tr');
    expect(theadRows).toHaveLength(1);
    const headers = Array.from(theadRows[0].querySelectorAll('th')).map(
      (h) => h.textContent!,
    );
    expect(headers).toEqual(['Name', 'Size', 'Modified', 'Actions']);
  });

  it('always creates a <tbody>, even when there are no data rows', async () => {
    const { results } = await setupCleared();
    renderBrowse(browseResult({ path: '', parent: null, entries: [] }));
    const table = results.querySelector('table')!;
    expect(table.querySelector('tbody')).toBeTruthy();
    expect(dataRows(table)).toHaveLength(0);
  });

  it('places header <th>s in <thead> and data <td>s in <tbody> (never mixed)', async () => {
    const { results } = await setupCleared();
    renderBrowse(browseResult({ path: 'docs', entries: [fileEntry({ name: 'a.txt' })] }));
    const table = results.querySelector('table')!;
    // Every th lives under thead; every td lives under tbody.
    expect(table.querySelectorAll('thead td')).toHaveLength(0);
    expect(table.querySelectorAll('tbody th')).toHaveLength(0);
    expect(table.querySelectorAll('thead th').length).toBeGreaterThan(0);
    expect(table.querySelectorAll('tbody td').length).toBeGreaterThan(0);
